SELECT MAX(start_lat) AS max_lat
FROM event_locations
WHERE location_description = 'Lake near a forest';

SELECT SUM(fatalities) AS total_fatalities
FROM tornado_events
WHERE scale = 1;

SELECT event_id 
FROM tornado_events 
WHERE fatalities > 10;

SELECT MAX(fatalities * 2) AS max_doubled_fatalities
FROM tornado_events
WHERE scale = 5;

SELECT location_description, city
FROM event_locations
ORDER BY location_description;

SELECT event_description
FROM tornado_events
ORDER BY fatalities DESC;

SELECT MAX(peak_wind_speed) AS fiercest_gust
FROM tornado_events
WHERE date = '1950-01-03' AND state = 'IL';

SELECT state, MAX(peak_wind_speed) as fastest_gust_of_wind
FROM tornado_events
GROUP BY state;

SELECT county, MIN(start_lat) AS lowest_start_lat
FROM event_locations
GROUP BY county;

SELECT max_wind_speed
FROM scales
WHERE scale_id = 0;
